We can leverage `object.__getattribute__` and `object.__setattr__` here.

It isn't the most fun, but works:

```python
from ddtrace.utils.attrdict import AttrDict


class Custom(AttrDict):
    def __init__(self, *args, **kwargs):
        super(Custom, self).__init__(*args, **kwargs)
        object.__setattr__(self, 'config', object())
        object.__setattr__(self, 'name', 'CustomName')

    def __getattribute__(self, key):
        try:
            return object.__getattribute__(self, key)
        except AttributeError:
            pass

        return self[key]

    def __setattr__(self, key, value):
        if hasattr(self, key):
            object.__setattr__(self, key, value)
        else:
            self[key] = value
```


